export const s_ChecksCreateRequestBody = z.intersection(
  z.object({
    name: z.string(),
    head_sha: z.string(),
    details_url: z.string().optional(),
    external_id: z.string().optional(),
    status: z
      .enum([
        "queued",
        "in_progress",
        "completed",
        "waiting",
        "requested",
        "pending",
      ])
      .optional()
      .default("queued"),
    started_at: z.iso.datetime({offset: true}).optional(),
    conclusion: z
      .enum([
        "action_required",
        "cancelled",
        "failure",
        "neutral",
        "success",
        "skipped",
        "stale",
        "timed_out",
      ])
      .optional(),
    completed_at: z.iso.datetime({offset: true}).optional(),
    output: z
      .object({
        title: z.string(),
        summary: z.string().max(65535),
        text: z.string().max(65535).optional(),
        annotations: z
          .array(
            z.object({
              path: z.string(),
              start_line: z.coerce.number(),
              end_line: z.coerce.number(),
              start_column: z.coerce.number().optional(),
              end_column: z.coerce.number().optional(),
              annotation_level: z.enum(["notice", "warning", "failure"]),
              message: z.string(),
              title: z.string().optional(),
              raw_details: z.string().optional(),
            }),
          )
          .max(50)
          .optional(),
        images: z
          .array(
            z.object({
              alt: z.string(),
              image_url: z.string(),
              caption: z.string().optional(),
            }),
          )
          .optional(),
      })
      .optional(),
    actions: z
      .array(
        z.object({
          label: z.string().max(20),
          description: z.string().max(40),
          identifier: z.string().max(20),
        }),
      )
      .max(3)
      .optional(),
  }),
  z.union([
    z.intersection(
      z.object({
        status: z.literal("completed"),
        conclusion: z.enum([
          "action_required",
          "cancelled",
          "failure",
          "neutral",
          "success",
          "skipped",
          "stale",
          "timed_out",
        ]),
      }),
      z.record(z.string(), z.unknown()),
    ),
    z.intersection(
      z.object({status: z.enum(["queued", "in_progress"]).optional()}),
      z.record(z.string(), z.unknown()),
    ),
  ]),
)

